import React, { useState, useEffect } from 'react';
import { Search, Plus, X, Tag, Save, Loader2 } from 'lucide-react';

const TRANSLATIONS = {
  "en-US": {
    "projectStatusFinder": "Project Status Finder",
    "projectDescription": "Project Description",
    "projectDescriptionPlaceholder": "e.g., Q4 Marketing Campaign",
    "slackChannels": "Slack Channels",
    "loadGroup": "Load group...",
    "groupNamePlaceholder": "Group name",
    "saveButton": "Save",
    "saveGroupTitle": "Save group",
    "channelNamePlaceholder": "channel-name",
    "addChannel": "Add Channel",
    "findProjectStatus": "Find Project Status",
    "searching": "Searching...",
    "results": "Results",
    "errorEnterGroupName": "Please enter a group name to save",
    "errorAddChannel": "Please add at least one channel before saving",
    "groupSavedSuccess": "✓ Group \"{groupName}\" saved successfully!",
    "errorSavingGroup": "Error saving group: {error}",
    "errorLoadingGroup": "Error loading group: {error}",
    "errorEnterProjectDesc": "Please enter a project description",
    "errorAddSlackChannel": "Please add at least one Slack channel",
    "noResultsFound": "No results found.",
    "errorPrefix": "Error: {error}",
    "searchPrompt": "Search the following Slack channels for information about this project: \"{projectDesc}\"\n\nChannels to search: {channelList}\n\nFor each channel that has relevant information, provide a markdown-formatted response with these three sections:\n\n**Current Status**\nProvide a brief summary of the project's current status based on recent messages.\n\n**Key People**\nList the names of people involved in this project (comma-separated, in bold).\n\n**Project Timeline**\nList key dates and milestones mentioned in the discussions.\n\nIf no relevant information is found in a channel, mention that briefly. Format your response clearly with proper markdown headers and emphasis. Please respond in {locale} language",
    "continuationPrompt": "Please continue."
  },
  /* LOCALE_PLACEHOLDER_START */
  "es-ES": {
    "projectStatusFinder": "Buscador de Estado de Proyecto",
    "projectDescription": "Descripción del Proyecto",
    "projectDescriptionPlaceholder": "ej., Campaña de Marketing Q4",
    "slackChannels": "Canales de Slack",
    "loadGroup": "Cargar grupo...",
    "groupNamePlaceholder": "Nombre del grupo",
    "saveButton": "Guardar",
    "saveGroupTitle": "Guardar grupo",
    "channelNamePlaceholder": "nombre-del-canal",
    "addChannel": "Agregar Canal",
    "findProjectStatus": "Buscar Estado del Proyecto",
    "searching": "Buscando...",
    "results": "Resultados",
    "errorEnterGroupName": "Por favor ingrese un nombre de grupo para guardar",
    "errorAddChannel": "Por favor agregue al menos un canal antes de guardar",
    "groupSavedSuccess": "✓ Grupo \"{groupName}\" guardado exitosamente!",
    "errorSavingGroup": "Error al guardar grupo: {error}",
    "errorLoadingGroup": "Error al cargar grupo: {error}",
    "errorEnterProjectDesc": "Por favor ingrese una descripción del proyecto",
    "errorAddSlackChannel": "Por favor agregue al menos un canal de Slack",
    "noResultsFound": "No se encontraron resultados.",
    "errorPrefix": "Error: {error}",
    "searchPrompt": "Busca en los siguientes canales de Slack información sobre este proyecto: \"{projectDesc}\"\n\nCanales a buscar: {channelList}\n\nPara cada canal que tenga información relevante, proporciona una respuesta en formato markdown con estas tres secciones:\n\n**Estado Actual**\nProporciona un breve resumen del estado actual del proyecto basado en mensajes recientes.\n\n**Personas Clave**\nEnumera los nombres de las personas involucradas en este proyecto (separados por comas, en negrita).\n\n**Cronograma del Proyecto**\nEnumera fechas clave y hitos mencionados en las discusiones.\n\nSi no se encuentra información relevante en un canal, menciónalo brevemente. Formatea tu respuesta claramente con encabezados markdown apropiados y énfasis. Por favor responde en idioma {locale}",
    "continuationPrompt": "Por favor continúa."
  }
  /* LOCALE_PLACEHOLDER_END */
};

const appLocale = '{{APP_LOCALE}}';
const browserLocale = navigator.languages?.[0] || navigator.language || 'en-US';
const findMatchingLocale = (locale) => {
  if (TRANSLATIONS[locale]) return locale;
  const lang = locale.split('-')[0];
  const match = Object.keys(TRANSLATIONS).find(key => key.startsWith(lang + '-'));
  return match || 'en-US';
};
const locale = (appLocale !== '{{APP_LOCALE}}') ? findMatchingLocale(appLocale) : findMatchingLocale(browserLocale);
const t = (key, replacements = {}) => {
  let text = TRANSLATIONS[locale]?.[key] || TRANSLATIONS['en-US'][key] || key;
  Object.keys(replacements).forEach(placeholder => {
    text = text.replace(new RegExp(`\\{${placeholder}\\}`, 'g'), replacements[placeholder]);
  });
  return text;
};

const ProjectStatusFinder = () => {
  const [projectDesc, setProjectDesc] = useState('');
  const [channels, setChannels] = useState(['']);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState('');
  const [groupName, setGroupName] = useState('');
  const [savedGroups, setSavedGroups] = useState([]);
  const [selectedGroup, setSelectedGroup] = useState('');
  const [error, setError] = useState('');

  useEffect(() => {
    loadSavedGroups();
  }, []);

  const loadSavedGroups = async () => {
    try {
      const groups = await window.storage.list('channel_group:');
      if (groups && groups.keys) {
        setSavedGroups(groups.keys);
      }
    } catch (error) {
      console.log('No saved groups yet');
    }
  };

  const sanitizeName = (name) => {
    return name.replace(/[\s'"\/\\]/g, '_');
  };

  const saveGroup = async () => {
    if (!groupName.trim()) {
      setError(t('errorEnterGroupName'));
      setTimeout(() => setError(''), 3000);
      return;
    }

    if (channels.filter(c => c.trim()).length === 0) {
      setError(t('errorAddChannel'));
      setTimeout(() => setError(''), 3000);
      return;
    }

    const sanitized = sanitizeName(groupName.trim());
    const key = `channel_group:${sanitized}`;

    try {
      await window.storage.set(key, JSON.stringify(channels.filter(c => c.trim())));
      setError('');
      const originalGroupName = groupName;
      setGroupName('');
      loadSavedGroups();
      setError(t('groupSavedSuccess', { groupName: originalGroupName }));
      setTimeout(() => setError(''), 3000);
    } catch (error) {
      setError(t('errorSavingGroup', { error: error.message }));
      setTimeout(() => setError(''), 3000);
    }
  };

  const loadGroup = async (key) => {
    try {
      const data = await window.storage.get(key);
      if (data && data.value) {
        const channelList = JSON.parse(data.value);
        setChannels(channelList.length > 0 ? channelList : ['']);
      }
    } catch (error) {
      alert(t('errorLoadingGroup', { error: error.message }));
    }
  };

  const addChannel = () => {
    setChannels([...channels, '']);
  };

  const removeChannel = (index) => {
    if (channels.length > 1) {
      setChannels(channels.filter((_, i) => i !== index));
    }
  };

  const updateChannel = (index, value) => {
    const newChannels = [...channels];
    newChannels[index] = value;
    setChannels(newChannels);
  };

  const findProjectStatus = async () => {
    const validChannels = channels.filter(c => c.trim());

    if (!projectDesc.trim()) {
      setError(t('errorEnterProjectDesc'));
      setTimeout(() => setError(''), 3000);
      return;
    }

    if (validChannels.length === 0) {
      setError(t('errorAddSlackChannel'));
      setTimeout(() => setError(''), 3000);
      return;
    }

    setLoading(true);
    setResult('');
    setError('');

    try {
      const channelList = validChannels.map(c => `#${c.trim().replace(/^#/, '')}`).join(', ');

      const prompt = t('searchPrompt', { 
        projectDesc, 
        channelList,
        locale: locale.split('-')[0] 
      });

      let messages = [{ role: "user", content: prompt }];
      let accumulatedText = "";

      while (true) {
        const response = await fetch("https://api.anthropic.com/v1/messages", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            model: "claude-sonnet-4-20250514",
            max_tokens: 1000,
            messages: messages,
            mcp_servers: [
              {
                type: "url",
                url: "https://mcp.slack.com/mcp",
                name: "slack-mcp"
              }
            ]
          })
        });

        const data = await response.json();

        const textContent = data.content
          .filter(item => item.type === "text")
          .map(item => item.text)
          .join("\n\n");

        if (textContent) {
          accumulatedText += (accumulatedText ? "\n\n" : "") + textContent;
        }

        if (data.stop_reason === "pause_turn") {
          messages.push({
            role: "assistant",
            content: data.content
          });

          messages.push({
            role: "user",
            content: t('continuationPrompt')
          });

          continue;
        } else {
          break;
        }
      }

      setResult(accumulatedText || t('noResultsFound'));
    } catch (error) {
      setResult(t('errorPrefix', { error: error.message }));
    } finally {
      setLoading(false);
    }
  };

  const renderMarkdown = (text) => {
    let html = text;

    html = html.replace(/^### (.*$)/gim, '<h3 class="text-lg font-bold mt-4 mb-2">$1</h3>');
    html = html.replace(/^## (.*$)/gim, '<h2 class="text-xl font-bold mt-4 mb-2">$1</h2>');
    html = html.replace(/^# (.*$)/gim, '<h1 class="text-2xl font-bold mt-4 mb-2">$1</h1>');

    html = html.replace(/\*\*(.*?)\*\*/g, '<strong class="font-bold">$1</strong>');

    html = html.replace(/\*(.*?)\*/g, '<em class="italic">$1</em>');

    html = html.replace(/```(.*?)```/gs, '<pre class="bg-gray-100 p-2 rounded my-2 overflow-x-auto"><code>$1</code></pre>');

    html = html.replace(/`(.*?)`/g, '<code class="bg-gray-100 px-1 rounded">$1</code>');

    html = html.replace(/\n/g, '<br />');

    return html;
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-indigo-500 via-purple-500 to-purple-600 p-8">
      <div className="max-w-4xl mx-auto">
        <div className="bg-white rounded-lg shadow-2xl p-8 mb-6">
          <h1 className="text-3xl font-bold text-gray-800 mb-6 flex items-center gap-2">
            <Search className="text-indigo-600" />
            {t('projectStatusFinder')}
          </h1>

          <div className="mb-6">
            <label className="block text-sm font-medium text-gray-700 mb-2">
              {t('projectDescription')}
            </label>
            <input
              type="text"
              value={projectDesc}
              onChange={(e) => setProjectDesc(e.target.value)}
              placeholder={t('projectDescriptionPlaceholder')}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500"
            />
          </div>

          {error && (
            <div className={`mb-4 p-3 rounded-lg ${error.startsWith('✓') ? 'bg-green-50 text-green-700 border border-green-200' : 'bg-red-50 text-red-700 border border-red-200'}`}>
              <p className="text-sm font-medium">{error}</p>
            </div>
          )}

          <div className="mb-6">
            <div className="flex items-center justify-between mb-3">
              <label className="block text-sm font-medium text-gray-700">
                {t('slackChannels')}
              </label>

              <div className="flex items-center gap-2">
                {savedGroups.length > 0 && (
                  <>
                    <Tag size={16} className="text-gray-400" />
                    <select
                      value={selectedGroup}
                      onChange={(e) => {
                        setSelectedGroup(e.target.value);
                        if (e.target.value) loadGroup(e.target.value);
                      }}
                      className="text-sm px-3 py-1 border border-gray-300 rounded-md focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 bg-white"
                    >
                      <option value="">{t('loadGroup')}</option>
                      {savedGroups.map((key) => (
                        <option key={key} value={key}>
                          {key.replace('channel_group:', '').replace(/_/g, ' ')}
                        </option>
                      ))}
                    </select>
                  </>
                )}

                <div className="flex items-center gap-1">
                  <input
                    type="text"
                    value={groupName}
                    onChange={(e) => setGroupName(e.target.value)}
                    placeholder={t('groupNamePlaceholder')}
                    className="text-sm px-3 py-1 border border-gray-300 rounded-md focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 w-32"
                  />
                  <button
                    onClick={saveGroup}
                    className="text-sm px-3 py-1 bg-indigo-600 text-white rounded-md hover:bg-indigo-700 transition-colors font-medium"
                    title={t('saveGroupTitle')}
                  >
                    {t('saveButton')}
                  </button>
                </div>
              </div>
            </div>

            {channels.map((channel, index) => (
              <div key={index} className="flex gap-2 mb-2">
                <input
                  type="text"
                  value={channel}
                  onChange={(e) => updateChannel(index, e.target.value)}
                  placeholder={t('channelNamePlaceholder')}
                  className="flex-1 px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500"
                />
                {channels.length > 1 && (
                  <button
                    onClick={() => removeChannel(index)}
                    className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                  >
                    <X size={20} />
                  </button>
                )}
              </div>
            ))}
            <button
              onClick={addChannel}
              className="mt-2 flex items-center gap-2 text-indigo-600 hover:text-indigo-700 font-medium"
            >
              <Plus size={20} />
              {t('addChannel')}
            </button>
          </div>

          <button
            onClick={findProjectStatus}
            disabled={loading}
            className="w-full flex items-center justify-center gap-2 px-6 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 disabled:bg-gray-400 disabled:cursor-not-allowed transition-colors font-medium"
          >
            {loading ? (
              <>
                <Loader2 className="animate-spin" size={20} />
                {t('searching')}
              </>
            ) : (
              <>
                <Search size={20} />
                {t('findProjectStatus')}
              </>
            )}
          </button>
        </div>

        {result && (
          <div className="bg-white rounded-lg shadow-2xl p-8">
            <h2 className="text-2xl font-bold text-gray-800 mb-4">{t('results')}</h2>
            <div 
              className="prose max-w-none text-gray-700"
              dangerouslySetInnerHTML={{ __html: renderMarkdown(result) }}
            />
          </div>
        )}
      </div>
    </div>
  );
};

export default ProjectStatusFinder;
